"use client"

import { useState, useEffect } from "react"
import { useSession } from "next-auth/react"
import { CalendarView } from "@/components/admin/square-calendar/calendar-view"
import { useCalendarStore } from "@/lib/square-calendar-store/calendar-store"
import { Event } from "@/lib/square-calendar-mock-data/events"

interface Booking {
	id: string
	service: {
		id: string
		name: string
		price: number
	}
	userName: string
	phone: string
	email?: string | null
	date: string
	time: string
	status: string
	paymentMethod: string
	user?: {
		id: string
		name: string | null
		email: string
		phone: string | null
	} | null
	photos?: Array<{ url: string }>
	createdAt?: string
}

interface BookingCalendarProps {
	userId?: string | null
}

export function BookingCalendar({ userId }: BookingCalendarProps) {
	const { data: session } = useSession()
	const setEvents = useCalendarStore(state => state.setEvents)
	const [isLoading, setIsLoading] = useState(true)

	// To handle time increment logic cleanly for events:
	const generateEndTime = (timeStr: string) => {
		// Just adds 1 hour to something like "10:00 AM" or "10:00"
		return timeStr; // For simplicity, we just reuse the time or parse it later if we need to
	}

	const fetchBookings = async () => {
		setIsLoading(true)
		try {
			// Fetch all bookings (without startDate/endDate to get full details)
			let url = `/api/v1/bookings?limit=1000`
			if (userId) {
				url += `&userId=${userId}`
			}

			const response = await fetch(url)
			if (response.ok) {
				const data = await response.json()
				const fetchedBookings: Booking[] = data.bookings || []
				
				// Map into Event shape required by CalendarView
				const baseEvents = fetchedBookings.map((b) => {
					// Date format: "YYYY-MM-DD"
					const dateStr = new Date(b.date).toISOString().split("T")[0]
					
					// Parse "10:00 AM" to "10:00" format expected by square UI
					let time24 = b.time;
					if (b.time.includes("AM") || b.time.includes("PM")) {
						const [time, modifier] = b.time.split(" ");
						let [hours, minutes] = time.split(":");
						if (hours === "12") hours = "00";
						if (modifier === "PM") hours = (parseInt(hours, 10) + 12).toString();
						time24 = `${hours.padStart(2, '0')}:${minutes}`;
					}
					
					// Create 1 hr duration
					const [hrs, mins] = time24.split(":");
					const endHrs = (parseInt(hrs, 10) + 1).toString().padStart(2, "0");
					const end24 = `${endHrs}:${mins}`;

					return {
						id: b.id,
						title: `${b.service.name} (${b.status})`,
						startTime: time24,
						endTime: end24,
						date: dateStr,
						participants: [b.userName, b.phone].filter(Boolean) as string[],
					}
				})
				
				setEvents(baseEvents)
			}
		} catch (error) {
			console.error("Failed to fetch bookings:", error)
		} finally {
			setIsLoading(false)
		}
	}

	useEffect(() => {
		fetchBookings()
	}, [userId])

	return (
		<div className="space-y-4">
			<div className="bg-card rounded-lg p-6 border shadow-sm border-border min-h-[700px]">
				{isLoading ? (
					<div className="text-center py-8 text-muted-foreground">Loading bookings...</div>
				) : (
					<CalendarView />
				)}
			</div>
		</div>
	)
}

